import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { GoogleLogin } from '@react-oauth/google';

const StudentLogin = () => {
  const { login, googleLogin, googleRegister } = useContext(AuthContext);
  const navigate = useNavigate();

  const [formData, setFormData] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Google Registration State
  const [requiresRegistration, setRequiresRegistration] = useState(false);
  const [registrationData, setRegistrationData] = useState({
    role: 'student',
    subject: '',
    googleToken: '',
    name: '',
    email: '',
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    if (requiresRegistration) {
      setRegistrationData((prev) => ({ ...prev, [name]: value }));
    } else {
      setFormData((prev) => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      await login({ ...formData, role: 'student' });
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSuccess = async (credentialResponse) => {
    setError('');
    setLoading(true);

    try {
      const res = await googleLogin({ token: credentialResponse.credential, role: 'student' });

      if (res?.requiresRegistration) {
        setRequiresRegistration(true);
        setRegistrationData((prev) => ({
          ...prev,
          googleToken: res.googleToken,
          name: res.name,
          email: res.email,
        }));
      } else {
        navigate('/dashboard');
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Google Login failed');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleError = () => {
    setError('Google Login failed completely.');
  };

  const handleGoogleRegisterSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      await googleRegister(registrationData);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Google Registration failed');
    } finally {
      setLoading(false);
    }
  };

  if (requiresRegistration) {
    return (
      <>
        <div className="animated-bg">
          <div className="blob blob-1"></div>
          <div className="blob blob-2"></div>
          <div className="blob blob-3"></div>
        </div>
        <div style={{ display: 'flex', minHeight: '100vh', alignItems: 'center', justifyContent: 'center', padding: '2rem' }}>
          <div className="island-card" style={{ width: '100%', maxWidth: '500px', padding: '3rem' }}>
            <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
              <span className="nav-unread" style={{ background: 'var(--accent-light)', color: 'var(--accent-primary)', padding: '4px 12px', display: 'inline-block', marginBottom: '1rem' }}>Complete Profile</span>
              <h2 className="island-title" style={{ fontSize: '1.8rem', marginBottom: '0.5rem' }}>Welcome, {registrationData.name.split(' ')[0]}!</h2>
              <p className="island-desc">Please complete your profile to finish creating your account.</p>
            </div>

            {error && (
              <div style={{ background: 'rgba(239, 68, 68, 0.2)', border: '1px solid var(--status-danger)', padding: '1rem', borderRadius: '12px', marginBottom: '1.5rem', display: 'flex', justifyContent: 'space-between' }}>
                <span>{error}</span>
                <button onClick={() => setError('')} style={{ color: 'white', border: 'none', background: 'transparent', cursor: 'pointer' }}>x</button>
              </div>
            )}

            <form onSubmit={handleGoogleRegisterSubmit}>
              <div style={{ marginBottom: '1.5rem' }}>
                <label htmlFor="role" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-muted)', fontWeight: 'bold' }}>I am a...</label>
                <select
                  className="form-input"
                  style={{ width: '100%' }}
                  id="role"
                  name="role"
                  value={registrationData.role}
                  onChange={handleChange}
                  required
                >
                  <option value="student">Student</option>
                  <option value="staff">Staff / Guide</option>
                </select>
              </div>

              {registrationData.role === 'staff' && (
                <div style={{ marginBottom: '1.5rem' }}>
                  <label htmlFor="subject" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-muted)', fontWeight: 'bold' }}>Department / Subject</label>
                  <input
                    type="text"
                    className="form-input"
                    style={{ width: '100%' }}
                    id="subject"
                    name="subject"
                    value={registrationData.subject}
                    onChange={handleChange}
                    required
                    placeholder="e.g. Computer Science"
                  />
                </div>
              )}

              <button type="submit" className="btn btn-primary" style={{ width: '100%', padding: '0.75rem' }} disabled={loading}>
                {loading ? 'Saving...' : 'Complete Registration'}
              </button>
              <div style={{ textAlign: 'center', marginTop: '1rem' }}>
                <button type="button" style={{ background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer' }} onClick={() => setRequiresRegistration(false)}>
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      </>
    );
  }

  return (
    <>
      <div className="animated-bg">
        <div className="blob blob-1"></div>
        <div className="blob blob-2"></div>
        <div className="blob blob-3"></div>
      </div>
      <div style={{ display: 'flex', minHeight: '100vh', alignItems: 'center', justifyContent: 'center', padding: '2rem' }}>
        <div className="island-card" style={{ width: '100%', maxWidth: '500px', padding: '3rem' }}>
          <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
            <span className="nav-unread" style={{ background: 'var(--accent-light)', color: 'var(--accent-primary)', padding: '4px 12px', display: 'inline-block', marginBottom: '1rem' }}>AskDesk</span>
            <h2 className="island-title" style={{ fontSize: '1.8rem', marginBottom: '0.5rem' }}>AskDesk Login</h2>
            <p className="island-desc">Access your dashboard and manage academic doubt resolution.</p>
          </div>

          {error && (
            <div style={{ background: 'rgba(239, 68, 68, 0.2)', border: '1px solid var(--status-danger)', padding: '1rem', borderRadius: '12px', marginBottom: '1.5rem', display: 'flex', justifyContent: 'space-between' }}>
              <span>{error}</span>
              <button onClick={() => setError('')} style={{ color: 'white', border: 'none', background: 'transparent', cursor: 'pointer' }}>x</button>
            </div>
          )}

          <form onSubmit={handleSubmit}>
            <div style={{ marginBottom: '1.5rem' }}>
              <label htmlFor="email" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-muted)', fontWeight: 'bold' }}>
                Email Address
              </label>
              <input
                type="email"
                className="form-input"
                style={{ width: '100%' }}
                id="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
                placeholder="your@email.com"
              />
            </div>

            <div style={{ marginBottom: '1.5rem' }}>
              <label htmlFor="password" style={{ display: 'block', marginBottom: '0.5rem', color: 'var(--text-muted)', fontWeight: 'bold' }}>
                Password
              </label>
              <input
                type="password"
                className="form-input"
                style={{ width: '100%' }}
                id="password"
                name="password"
                value={formData.password}
                onChange={handleChange}
                required
                placeholder="Enter your password"
              />
            </div>

            <button
              type="submit"
              className="btn btn-primary"
              style={{ width: '100%', padding: '0.75rem' }}
              disabled={loading}
            >
              {loading ? 'Logging in...' : 'Login'}
            </button>

            <div style={{ display: 'flex', alignItems: 'center', margin: '2rem 0', color: 'var(--text-muted)' }}>
              <div style={{ flex: 1, height: '1px', background: 'rgba(255,255,255,0.1)' }}></div>
              <span style={{ padding: '0 1rem', fontSize: '0.85rem' }}>OR</span>
              <div style={{ flex: 1, height: '1px', background: 'rgba(255,255,255,0.1)' }}></div>
            </div>

            <div style={{ display: 'flex', justifyContent: 'center' }}>
              <GoogleLogin
                onSuccess={handleGoogleSuccess}
                onError={handleGoogleError}
                useOneTap
                theme="filled_blue"
                shape="pill"
              />
            </div>
          </form>

          <div style={{ textAlign: 'center', marginTop: '2rem' }}>
            <p style={{ color: 'var(--text-muted)', margin: 0 }}>
              Don't have an account?{' '}
              <a href="/register" style={{ color: 'var(--accent-primary)', fontWeight: 'bold', textDecoration: 'none' }}>
                Register here
              </a>
            </p>
          </div>
        </div>
      </div>
    </>
  );
};

export default StudentLogin;
